import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty list when given empty list");
  it.todo("should kill a single live cell with no neighbors (underpopulation)");
  it.todo("should kill two adjacent live cells, each with only one neighbor (underpopulation)");
  it.todo("should keep a live cell alive when it has 2 live neighbors (survival)");
  it.todo("should kill the center cell of a 3x3 block which has more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
  it.todo("should keep a 2x2 block unchanged (still life)");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
  it.todo("should handle negative coordinates correctly");
});
